            dispatchQ4MVf16io(
                device,
                encoder,
                a.v_proj,
                a.norm_out,
                a.v,
                kv_qmv,
            );
        }
    } else {
        dispatchQMVf16io(
            device,
            encoder,
            a.q_proj,
            a.norm_out,
            a.q,
            q_qmv,
        );
        if (can_fuse_kv) {
            dispatchQMVFusedPairf16io(
                device,
